CREATE TABLE "RewriteCostLog" (
  "id" TEXT PRIMARY KEY,
  "userId" TEXT,
  "requestId" TEXT,
  "requesterEmail" TEXT,
  "rawMessageText" TEXT,
  "draftReplyText" TEXT,
  "finalRewriteText" TEXT,
  "databaseUrlNote" TEXT,
  "strategyVersion" TEXT,
  "scenario" TEXT,
  "tonePreset" TEXT,
  "status" TEXT,
  "errorCode" TEXT,
  "startedAt" TEXT,
  "finishedAt" TEXT,
  "durationMs" INTEGER,
  "draftAiLikePercent" INTEGER,
  "rewriteAiLikePercent" INTEGER,
  "changePoints" INTEGER,
  "internalStrategies" INTEGER,
  "repairCandidates" INTEGER,
  "rejectedCandidates" INTEGER,
  "usedEscalation" INTEGER,
  "openAiInputTokens" INTEGER,
  "openAiOutputTokens" INTEGER,
  "openAiCostUsd" REAL,
  "saplingCallCount" INTEGER,
  "saplingCharacters" INTEGER,
  "saplingCostUsd" REAL,
  "totalEstimatedCostUsd" REAL,
  "createdAt" TEXT
);

CREATE TABLE "RewriteProviderCall" (
  "id" TEXT PRIMARY KEY,
  "costLogId" TEXT,
  "provider" TEXT,
  "role" TEXT,
  "model" TEXT,
  "inputTokens" INTEGER,
  "outputTokens" INTEGER,
  "characters" INTEGER,
  "estimatedCostUsd" REAL,
  "latencyMs" INTEGER,
  "success" INTEGER,
  "errorCode" TEXT,
  "createdAt" TEXT
);
